// Input Validation & Normalization for CBS Strategic Evaluation
// Validates incoming request and normalizes data structure
// Preserves all Universal Contract fields from WF-0 Trigger

const uuidv4 = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random() * 16 | 0; return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16); });

// Get input from Workflow-0 Trigger
const inputItems = $input.all();

if (inputItems.length === 0) {
  throw new Error('No input data received from Workflow-0 Trigger');
}

const inputData = inputItems[0].json;

// Get workflow configuration
const config = $('Workflow Configuration').first().json;

// Define mandatory fields
const mandatoryFields = [
  'request_id',
  'intent_summary',
  'department',
  'task_type',
  'risk_level',
  'urgency',
  'mode'
];

// Validate mandatory fields
const missingFields = mandatoryFields.filter(field => !inputData[field]);

if (missingFields.length > 0) {
  throw new Error(`Missing mandatory fields: ${missingFields.join(', ')}`);
}

// Validate task_type is 'strategic'
if (inputData.task_type !== 'strategic') {
  throw new Error(`Invalid task_type: '${inputData.task_type}'. CBS only processes 'strategic' tasks.`);
}

// Generate strategy_id
const strategy_id = uuidv4();

// Build normalized output schema
// Preserve all Universal Contract fields from WF-0 Trigger
const normalizedOutput = {
  // Universal Contract fields (preserved from WF-0 Trigger)
  request_id: inputData.request_id,
  mode: inputData.mode,
  confidence: inputData.confidence || null,
  risk_level: inputData.risk_level,
  payload: inputData.payload || {},
  audit: inputData.audit || {},

  // CBS-specific fields
  strategy_id: strategy_id,
  intent_summary: inputData.intent_summary,
  timestamp: new Date().toISOString(),
  workflow_name: config.workflow_name || 'WF-1: CBS Strategic Evaluation',

  // Preserve additional fields for context
  department: inputData.department,
  task_type: inputData.task_type,
  urgency: inputData.urgency,

  // Keep original request for full context
  original_request: inputData
};

return [normalizedOutput];

