  };

  console.log('=== NO-GO DECISION LOGGED ===');
  console.log(JSON.stringify(logEntry, null, 2));
  console.log('============================');
}

// Return input data unchanged
return items;

// Log CREA rejection details
const inputData = $input.all();

for (const item of inputData) {
  const strategyId = item.json.strategy_id || 'UNKNOWN';
  const creaReason = item.json.crea_rejection_reason || item.json.rejection_reason || 'No reason provided';
  const timestamp = new Date().toISOString();

  console.log('=== CREA REJECTION LOGGED ===');
  console.log('Strategy ID:', strategyId);
  console.log('CREA Rejection Reason:', creaReason);
  console.log('Timestamp:', timestamp);
  console.log('============================');
}

// Return input data unchanged
return inputData;

// Consolidate & Analyze Feedback from All Departments
// This code processes aggregated department responses and creates a unified strategic plan

const items = $input.all();

// Initialize consolidated data structure
const consolidatedData = {
  final_decision: 'go', // Default to 'go', will be updated based on analysis
  department_feedback: {
    finance: null,
    operations: null,
    marketing: null,
    sales: null,
    rnd: null
  },
  synergies: [],
  conflicts: [],
  recommended_next_steps: [],
  warnings: []
};

// Track decision votes
const decisionVotes = {
  go: 0,
  no_go: 0,
  revise: 0
};

// Process each department response
for (const item of items) {
  const data = item.json;

  // Determine which department this response is from
  let department = null;
  if (data.department) {
    department = data.department.toLowerCase();
  } else if (data.source) {
    department = data.source.toLowerCase();
  }

  // Map department names to standard keys
  const deptMapping = {
    'finance': 'finance',
    'cfo': 'finance',
    'operations': 'operations',
    'coo': 'operations',
    'marketing': 'marketing',
    'cmo': 'marketing',
    'sales': 'sales',
    'cso': 'sales',
    'r&d': 'rnd',
    'rnd': 'rnd',
    'afa': 'rnd',
    'research': 'rnd'
  };

  const mappedDept = deptMapping[department] || department;

  // Store department feedback
  if (mappedDept && consolidatedData.department_feedback.hasOwnProperty(mappedDept)) {
    consolidatedData.department_feedback[mappedDept] = {
      recommendation: data.recommendation || data.decision || 'unknown',
      key_insights: data.key_insights || data.insights || [],
      concerns: data.concerns || data.risks || [],
      opportunities: data.opportunities || [],
      confidence_score: data.confidence_score || data.confidence || 0
    };

    // Count decision votes
    const decision = (data.recommendation || data.decision || '').toLowerCase();
    if (decision.includes('go') && !decision.includes('no')) {
      decisionVotes.go++;
    } else if (decision.includes('no_go') || decision.includes('reject')) {
      decisionVotes.no_go++;
    } else if (decision.includes('revise') || decision.includes('modify')) {
      decisionVotes.revise++;
    }
  }

  // Collect synergies
  if (data.synergies && Array.isArray(data.synergies)) {
    consolidatedData.synergies.push(...data.synergies);
  }

  // Collect warnings
  if (data.warnings && Array.isArray(data.warnings)) {
    consolidatedData.warnings.push(...data.warnings);
  }
  if (data.risks && Array.isArray(data.risks)) {
    consolidatedData.warnings.push(...data.risks);
  }
}

// Identify conflicts between departments
const departments = Object.keys(consolidatedData.department_feedback);
for (let i = 0; i < departments.length; i++) {
  for (let j = i + 1; j < departments.length; j++) {
    const dept1 = departments[i];
    const dept2 = departments[j];
    const feedback1 = consolidatedData.department_feedback[dept1];
    const feedback2 = consolidatedData.department_feedback[dept2];

    if (feedback1 && feedback2) {
      const rec1 = (feedback1.recommendation || '').toLowerCase();
      const rec2 = (feedback2.recommendation || '').toLowerCase();

      // Check for conflicting recommendations
      if ((rec1.includes('go') && rec2.includes('no_go')) ||
          (rec1.includes('no_go') && rec2.includes('go'))) {
        consolidatedData.conflicts.push({
          departments: [dept1, dept2],
          conflict_type: 'recommendation_mismatch',
          details: `${dept1} recommends '${feedback1.recommendation}' while ${dept2} recommends '${feedback2.recommendation}'`
        });
      }
    }
  }
}

// Determine final decision based on votes and conflicts
if (decisionVotes.no_go > 0 || consolidatedData.conflicts.length > 2) {
  consolidatedData.final_decision = 'no_go';
} else if (decisionVotes.revise > decisionVotes.go || consolidatedData.conflicts.length > 0) {
  consolidatedData.final_decision = 'revise';
} else {
  consolidatedData.final_decision = 'go';
}

// Generate recommended next steps based on analysis
if (consolidatedData.final_decision === 'go') {
  consolidatedData.recommended_next_steps.push(
    'Proceed with strategy implementation',
    'Establish cross-departmental coordination team',
    'Set up monitoring and KPI tracking systems'
  );
} else if (consolidatedData.final_decision === 'revise') {
  consolidatedData.recommended_next_steps.push(
    'Address identified conflicts between departments',
    'Revise strategy to incorporate departmental concerns',
    'Schedule follow-up review meeting with key stakeholders'
  );
} else {
  consolidatedData.recommended_next_steps.push(
    'Document reasons for rejection',
    'Explore alternative strategic approaches',
    'Conduct additional market research if needed'
  );
}

// Add specific next steps based on department feedback
for (const [dept, feedback] of Object.entries(consolidatedData.department_feedback)) {
  if (feedback && feedback.concerns && feedback.concerns.length > 0) {
    consolidatedData.recommended_next_steps.push(
      `Address ${dept} concerns: ${feedback.concerns.slice(0, 2).join(', ')}`
    );
  }
}

// Deduplicate arrays
consolidatedData.synergies = [...new Set(consolidatedData.synergies)];
consolidatedData.warnings = [...new Set(consolidatedData.warnings)];
consolidatedData.recommended_next_steps = [...new Set(consolidatedData.recommended_next_steps)];

// Return consolidated strategic plan
return [{ json: consolidatedData }];

