// Log Final Decision - Audit Trail
// Logs comprehensive decision data to console for audit purposes
// Emphasizes WF-1 authority boundaries: ADVISORY recommendation only

const items = $input.all();

for (const item of items) {
  const data = item.json;

  console.log('=== CBS FINAL DECISION AUDIT LOG ===');
  console.log('Timestamp:', new Date().toISOString());
  console.log('Workflow:', 'WF-1: CBS Strategic Evaluation');
  console.log('Authority Level:', 'ADVISORY ONLY - Execution authority belongs downstream');
  console.log('Strategy ID:', data.strategy_id || 'N/A');
  console.log('Request ID:', data.request_id || 'N/A');

  console.log('\n--- STANDARDIZED OUTPUT FIELDS ---');
  console.log('GO/NO-GO Decision:', data.go_no_go || 'N/A');
  console.log('Confidence Score:', data.confidence_score || 'N/A');
  console.log('Summary:', data.summary || 'N/A');
  console.log('Conditions:', JSON.stringify(data.conditions || [], null, 2));
  console.log('Warnings:', JSON.stringify(data.warnings || [], null, 2));
  console.log('Requires CEO Override:', data.requires_ceo_override || 'N/A');

  console.log('\n--- SCORES ---');
  console.log('Strategic Alignment Score:', data.strategic_alignment_score || 'N/A');
  console.log('Financial Viability Score:', data.financial_viability_score || 'N/A');
  console.log('Operational Feasibility Score:', data.operational_feasibility_score || 'N/A');
  console.log('Market Opportunity Score:', data.market_opportunity_score || 'N/A');
  console.log('Risk Assessment Score:', data.risk_assessment_score || 'N/A');
  console.log('Overall Score:', data.overall_score || 'N/A');

  console.log('\n--- DEPARTMENT APPROVALS ---');
  console.log('CFO Approval:', data.cfo_approval || 'N/A');
  console.log('COO Approval:', data.coo_approval || 'N/A');
  console.log('CMO Approval:', data.cmo_approval || 'N/A');
  console.log('CSO Approval:', data.cso_approval || 'N/A');
  console.log('AFA Approval:', data.afa_approval || 'N/A');
  console.log('CREA Approval:', data.crea_approval || 'N/A');

  console.log('\n--- FINAL DECISION ---');
  console.log('Decision:', data.final_decision || 'N/A');
  console.log('Recommendation:', data.recommendation || 'N/A');
  console.log('Mode:', data.mode || 'N/A');
  console.log('Risk Level:', data.risk_level || 'N/A');

  console.log('\n--- AUTHORITY REMINDER ---');
  console.log('⚠️  WF-1 provides ADVISORY recommendation only');
  console.log('⚠️  Execution authority belongs to downstream workflows');
  console.log('⚠️  This is NOT an execution approval');
  console.log('===================================\n');
}

// Return input data unchanged
return items;

// Universal Contract Validation for WF-1: CBS Strategic Evaluation
// Validates incoming Universal Workflow Contract from WF-0

const items = $input.all();

if (items.length === 0) {
  throw new Error(JSON.stringify({
    status: 'rejected',
    reason: 'No input data received from WF-0'
  }));
}

const inputData = items[0].json;

// Define mandatory Universal Contract fields
const mandatoryFields = [
  'request_id',
  'mode',
  'confidence',
  'risk_level',
  'payload',
  'audit'
];

// Validate mandatory fields
const missingFields = mandatoryFields.filter(field => !inputData.hasOwnProperty(field));

if (missingFields.length > 0) {
  throw new Error(JSON.stringify({
    status: 'rejected',
    reason: `Invalid or incomplete universal contract. Missing fields: ${missingFields.join(', ')}`
  }));
}

// Additional validation: ensure payload exists and has required structure
if (!inputData.payload || typeof inputData.payload !== 'object') {
  throw new Error(JSON.stringify({
    status: 'rejected',
    reason: 'Invalid or incomplete universal contract. Payload must be an object.'
  }));
}

// Additional validation: ensure audit exists and has required structure
if (!inputData.audit || typeof inputData.audit !== 'object') {
  throw new Error(JSON.stringify({
    status: 'rejected',
    reason: 'Invalid or incomplete universal contract. Audit must be an object.'
  }));
}

// Contract is valid - return validated input with all contract fields preserved
const validatedOutput = {
  request_id: inputData.request_id,
  mode: inputData.mode,
  confidence: inputData.confidence,
  risk_level: inputData.risk_level,
  payload: inputData.payload,
  audit: inputData.audit,
  // Preserve any additional fields
  ...inputData,
  // Add validation metadata
  contract_validated: true,
  validated_at: new Date().toISOString(),
  validated_by: 'WF-1: CBS Strategic Evaluation'
};

return [validatedOutput];

// Log Low Confidence Block
// Logs when a strategic decision is blocked due to low confidence score

const items = $input.all();

for (const item of items) {
  const data = item.json;

  console.log('=== WF-1 LOW CONFIDENCE BLOCK ===');
  console.log('Request ID:', data.request_id || 'N/A');
  console.log('Confidence Level:', data.confidence_score || 'N/A');
  console.log('Timestamp:', new Date().toISOString());
  console.log('Message: Decision is paused pending human approval');
  console.log('===================================\n');
}

// Return input data unchanged
return items;

// Final Output Sanitization & Normalization
// Creates a final sanitized output matching the required schema
// Pulls data directly from upstream nodes to ensure accuracy

const items = $input.all();
const modifiedItems = [];

for (const item of items) {
  // Get data from upstream nodes
  const triggerData = $('Workflow-0 Trigger').item.json;
  const cbsEvaluation = $('CBS Agent - Strategy Evaluation').item.json;
  const cbsFinalRecommendation = $('CBS Agent - Final Recommendation').item.json;

  // Convert boolean go_no_go to string decision
  const decision = cbsFinalRecommendation.go_no_go ? 'GO' : 'NO-GO';

  // Check if CREA reviewed (risk_level is 'high')
  const creaReviewed = triggerData.risk_level === 'high';

  // Create sanitized output with data from upstream nodes
  const sanitizedOutput = {
    workflow_id: 'WF-1',
    request_id: triggerData.request_id,
    status: 'completed',
    decision: decision,
    decision_summary: cbsFinalRecommendation.summary,
    confidence: triggerData.confidence,
    strategy_score: cbsEvaluation.scores.overall_score / 10,
    risk_level: triggerData.risk_level,
    human_approval_required: cbsFinalRecommendation.requires_ceo_override,
    crea_reviewed: creaReviewed,
    approvals: cbsFinalRecommendation.conditions || [],
    next_allowed_actions: [],
    logs: [
      {
        timestamp: new Date().toISOString(),
        message: 'Strategic evaluation completed',
        level: 'info'
      },
      {
        timestamp: new Date().toISOString(),
        message: 'SIMULATION ONLY – NO EXECUTION AUTHORIZED',
        level: 'warning'
      }
    ]
  };

  console.log('=== FINAL OUTPUT SANITIZATION ===');
  console.log('Request ID:', sanitizedOutput.request_id);
  console.log('Decision:', sanitizedOutput.decision);
  console.log('Confidence:', sanitizedOutput.confidence);
  console.log('Strategy Score:', sanitizedOutput.strategy_score);
  console.log('Risk Level:', sanitizedOutput.risk_level);
  console.log('Human Approval Required:', sanitizedOutput.human_approval_required);
  console.log('CREA Reviewed:', sanitizedOutput.crea_reviewed);
  console.log('Warning: SIMULATION ONLY – NO EXECUTION AUTHORIZED');
  console.log('Final Sanitized Output:', JSON.stringify(sanitizedOutput, null, 2));
  console.log('=================================');

  modifiedItems.push({ json: sanitizedOutput });
}

return modifiedItems;
